import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';

const Lancamento = () => {
  const [form, setForm] = useState({
    descricao: '', valor_total: '', loja: '', pedido: '', 
    nota_fiscal: '', parcelado: false, num_parcelas: 1, data_compra: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Calcula o valor da parcela se for parcelado
    const valorParcela = form.parcelado ? (form.valor_total / form.num_parcelas) : form.valor_total;

    const { data, error } = await supabase
      .from('compras')
      .insert([{
        ...form,
        valor_total: parseFloat(form.valor_total),
        num_parcelas: parseInt(form.num_parcelas)
      }]);

    if (error) {
      alert("Erro ao salvar: " + error.message);
    } else {
      alert("Despesa lançada com sucesso!");
      // Limpa o formulário
    }
  };

  return (
    <div style={{ maxWidth: '500px' }}>
      <h2>Novo Lançamento</h2>
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
        <input type="date" required onChange={e => setForm({...form, data_compra: e.target.value})} />
        <input placeholder="Descrição (ex: Notebook)" required onChange={e => setForm({...form, descricao: e.target.value})} />
        <input placeholder="Loja" onChange={e => setForm({...form, loja: e.target.value})} />
        <input placeholder="Valor Total" type="number" step="0.01" required onChange={e => setForm({...form, valor_total: e.target.value})} />
        
        <div style={{ background: '#f9f9f9', padding: '10px', borderRadius: '5px' }}>
          <label>
            <input type="checkbox" checked={form.parcelado} onChange={e => setForm({...form, parcelado: e.target.checked})} />
            Compra Parcelada?
          </label>
          
          {form.parcelado && (
            <div style={{ marginTop: '10px' }}>
              <input type="number" placeholder="Nº de Parcelas" min="1" onChange={e => setForm({...form, num_parcelas: e.target.value})} />
              <p><small>Valor de cada parcela: R$ {(form.valor_total / (form.num_parcelas || 1)).toFixed(2)}</small></p>
            </div>
          )}
        </div>

        <input placeholder="Nº Pedido (Opcional)" onChange={e => setForm({...form, pedido: e.target.value})} />
        <input placeholder="Nota Fiscal (Opcional)" onChange={e => setForm({...form, nota_fiscal: e.target.value})} />
        
        <button type="submit" style={{ padding: '10px', background: '#007bff', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
          Salvar Despesa
        </button>
      </form>
    </div>
  );
};

export default Lancamento;
